class TransactionValidator:
    """Validates transaction events against security rules."""

    @staticmethod
    def validate_transaction_id(tx_id: str) -> str:
        if not isinstance(tx_id, str):
            raise ValidationError("Transaction ID must be a string")
        if not TRANSACTION_ID_PATTERN.match(tx_id):
            raise ValidationError(f"Invalid transaction ID format: {tx_id[:50]}")
        return tx_id

    @staticmethod
    def validate_account_id(account_id: str, field_name: str) -> str:
        if not isinstance(account_id, str):
            raise ValidationError(f"{field_name} must be a string")
        if not ACCOUNT_ID_PATTERN.match(account_id):
            raise ValidationError(
                f"Invalid {field_name} format: {account_id[:50]}"
            )
        return account_id

    @staticmethod
    def validate_amount(amount) -> decimal.Decimal:
        try:
            # Convert to string first to avoid floating point issues
            if isinstance(amount, float):
                amount_dec = decimal.Decimal(str(amount))
            elif isinstance(amount, (int, str)):
                amount_dec = decimal.Decimal(str(amount))
            elif isinstance(amount, decimal.Decimal):
                amount_dec = amount
            else:
                raise ValidationError(f"Invalid amount type: {type(amount)}")
        except (decimal.InvalidOperation, ValueError):
            raise ValidationError(f"Invalid amount value")

        if amount_dec < MIN_TRANSACTION_AMOUNT:
            raise ValidationError(
                f"Amount {amount_dec} below minimum {MIN_TRANSACTION_AMOUNT}"
            )
        if amount_dec > MAX_TRANSACTION_AMOUNT:
            raise ValidationError(
                f"Amount {amount_dec} exceeds maximum {MAX_TRANSACTION_AMOUNT}"
            )
        # Ensure no more than 2 decimal places
        if amount_dec != amount_dec.quantize(decimal.Decimal("0.01")):
            raise ValidationError("Amount must have at most 2 decimal places")
        return amount_dec

    @staticmethod
    def validate_currency(currency: str) -> str:
        if not isinstance(currency, str):
            raise ValidationError("Currency must be a string")
        currency = currency.upper().strip()
        if currency not in ALLOWED_CURRENCIES:
            raise ValidationError(f"Unsupported currency: {currency[:10]}")
        return currency

    @staticmethod
    def validate_transaction_type(tx_type: str) -> str:
        if not isinstance(tx_type, str):
            raise ValidationError("Transaction type must be a string")
        tx_type = tx_type.lower().strip()
        if tx_type not in ALLOWED_TRANSACTION_TYPES:
            raise ValidationError(f"Invalid transaction type: {tx_type[:50]}")
        return tx_type

    @staticmethod
    def validate_timestamp(timestamp: str) -> str:
        if not isinstance(timestamp, str):
            raise ValidationError("Timestamp must be a string")
        try:
            dt = datetime.fromisoformat(timestamp.replace('Z', '+00:00'))
            # Reject timestamps too far in the future (5 minutes tolerance)
            now = datetime.now(timezone.utc)
            if dt.tzinfo:
                diff = (dt - now).total_seconds()
            else:
                diff = (dt - now.replace(tzinfo=None)).total_seconds()
            if diff > 300:
                raise ValidationError("Timestamp is too far in the future")
        except (ValueError, TypeError):
            raise ValidationError(f"Invalid timestamp format")
        return timestamp

    @staticmethod
    def sanitize_metadata(metadata) -> Dict:
        """Sanitize metadata - only allow simple string key-value pairs."""
        if metadata is None:
            return {}
        if not isinstance(metadata, dict):
            raise ValidationError("Metadata must be a dictionary")
        sanitized = {}
        # Limit metadata entries
        if len(metadata) > 20:
            raise ValidationError("Too many metadata entries (max 20)")
        for key, value in metadata.items():
            if not isinstance(key, str) or len(key) > 100:
                continue
            # Only allow string, int, float values - no nested objects
            if isinstance(value, str) and len(value) <= 500:
                sanitized[key] = value
            elif isinstance(value, (int, float)) and not isinstance(value, bool):
                sanitized[key] = value
        return sanitized

    @classmethod
    def validate_and_create(cls, data: dict) -> TransactionEvent:
        """Validate raw data and create an immutable TransactionEvent."""
        if not isinstance(data, dict):
            raise ValidationError("Transaction data must be a dictionary")

        # Check for required fields
        required_fields = {
            "transaction_id", "transaction_type", "source_account",
            "destination_account", "amount", "currency", "timestamp"
        }
        missing = required_fields - set(data.keys())
        if missing:
            raise ValidationError(f"Missing required fields: {missing}")

        return TransactionEvent(
            transaction_id=cls.validate_transaction_id(data["transaction_id"]),
            transaction_type=cls.validate_transaction_type(data["transaction_type"]),
            source_account=cls.validate_account_id(data["source_account"], "source_account"),
            destination_account=cls.validate_account_id(data["destination_account"], "destination_account"),
            amount=cls.validate_amount(data["amount"]),
            currency=cls.validate_currency(data["currency"]),
            timestamp=cls.validate_timestamp(data["timestamp"]),
            metadata=cls.sanitize_metadata(data.get("metadata")),
        )


def safe_json_deserializer(raw_bytes: bytes) -> Optional[dict]:
    """
    Safely deserialize JSON bytes. Never uses pickle or eval.
    Limits payload size to prevent DoS.
    """
    MAX_PAYLOAD_SIZE = 1024 * 64  # 64 KB max

    if raw_bytes is None:
        return None

    if len(raw_bytes) > MAX_PAYLOAD_SIZE:
        logger.warning(
            "Rejected oversized message: %d bytes (max %d)",
            len(raw_bytes), MAX_PAYLOAD_SIZE
        )
        return None

    try:
        data = json.loads(raw_bytes.decode("utf-8"))
        if not isinstance(data, dict):
            logger.warning("Deserialized value is not a dict, rejecting")
            return None
        return data
    except (json.JSONDecodeError, UnicodeDecodeError) as e:
        logger.warning("Failed to deserialize message: %s", e)
        return None


class TransactionHandlerRegistry:
    """
    Registry for transaction handlers. Uses explicit registration
    instead of dynamic code execution.
    """

    def __init__(self):
        self._handlers: Dict[str, Callable[[TransactionEvent], bool]] = {}

    def register(self, transaction_type: str, handler: Callable[[TransactionEvent], bool]):
        """Register a handler for a specific transaction type."""
        if transaction_type not in ALLOWED_TRANSACTION_TYPES:
            raise ValueError(
                f"Cannot register handler for unknown type: {transaction_type}"
            )
        if not callable(handler):
            raise TypeError("Handler must be callable")
        self._handlers[transaction_type] = handler
        logger.info("Registered handler for transaction type: %s", transaction_type)

    def get_handler(self, transaction_type: str) -> Optional[Callable[[TransactionEvent], bool]]:
        """Get handler for a transaction type from the whitelist."""
        if transaction_type not in ALLOWED_TRANSACTION_TYPES:
            logger.warning("Attempted to get handler for disallowed type: %s", transaction_type)
            return None
        return self._handlers.get(transaction_type)

    def has_handler(self, transaction_type: str) -> bool:
        return transaction_type in self._handlers


