class TransactionConsumer:
    """
    Kafka consumer for financial transaction events.
    Processes messages securely with validation and whitelisted handlers.
    """

    def __init__(
        self,
        bootstrap_servers: str = "localhost:9092",
        topics: Optional[list] = None,
        group_id: str = "transaction-processor-group",
        ssl_enabled: bool = False,
        ssl_cafile: Optional[str] = None,
        ssl_certfile: Optional[str] = None,
        ssl_keyfile: Optional[str] = None,
        sasl_mechanism: Optional[str] = None,
        sasl_username: Optional[str] = None,
        sasl_password: Optional[str] = None,
    ):
        if topics is None:
            topics = ["financial-transactions"]

        # Validate topic names
        topic_pattern = re.compile(r'^[a-zA-Z0-9._-]{1,249}$')
        for topic in topics:
            if not topic_pattern.match(topic):
                raise ValueError(f"Invalid topic name: {topic}")

        self._topics = topics
        self._handler_registry = TransactionHandlerRegistry()
        self._validator = TransactionValidator()
        self._running = False

        # Build consumer config
        consumer_config = {
            "bootstrap_servers": bootstrap_servers,
            "group_id": group_id,
            "auto_offset_reset": "earliest",
            "enable_auto_commit": False,  # Manual commit for reliability
            "value_deserializer": safe_json_deserializer,
            "max_poll_records": 100,
            "session_timeout_ms": 30000,
            "heartbeat_interval_ms": 10000,
            "max_poll_interval_ms": 300000,
        }

        # SSL/TLS configuration
        if ssl_enabled:
            consumer_config["security_protocol"] = "SSL"
            if ssl_cafile:
                consumer_config["ssl_cafile"] = ssl_cafile
            if ssl_certfile:
                consumer_config["ssl_certfile"] = ssl_certfile
            if ssl_keyfile:
                consumer_config["ssl_keyfile"] = ssl_keyfile

        # SASL configuration
        if sasl_mechanism:
            if ssl_enabled:
                consumer_config["security_protocol"] = "SASL_SSL"
            else:
                consumer_config["security_protocol"] = "SASL_PLAINTEXT"
            consumer_config["sasl_mechanism"] = sasl_mechanism
            if sasl_username:
                consumer_config["sasl_plain_username"] = sasl_username
            if sasl_password:
                consumer_config["sasl_plain_password"] = sasl_password

        self._consumer = KafkaConsumer(**consumer_config)

        # Register default handlers
        self._register_default_handlers()

    def _register_default_handlers(self):
        """Register the built-in transaction handlers."""
        self._handler_registry.register("deposit", handle_deposit)
        self._handler_registry.register("withdrawal", handle_withdrawal)
        self._handler_registry.register("transfer", handle_transfer)
        self._handler_registry.register("payment", handle_payment)
        self._handler_registry.register("refund", handle_refund)
        self._handler_registry.register("fee", handle_fee)

    def register_handler(
        self, transaction_type: str, handler: Callable[[TransactionEvent], bool]
    ):
        """Register a custom handler for a transaction type."""
        self._handler_registry.register(transaction_type, handler)

    def _process_message(self, raw_data: Optional[dict]) -> bool:
        """Process a single deserialized message."""
        if raw_data is None:
            logger.warning("Skipping null/invalid message")
            return False

        try:
            # Validate and create immutable event
            event = self._validator.validate_and_create(raw_data)
        except ValidationError as e:
            logger.warning("Validation failed: %s", e)
            # In production, send to dead-letter queue
            return False

        # Look up handler from registry (whitelist-based dispatch)
        handler = self._handler_registry.get_handler(event.transaction_type)
        if handler is None:
            logger.warning(
                "No handler registered for transaction type: %s (tx: %s)",
                event.transaction_type,
                event.transaction_id,
            )
            return False

        try:
            success = handler(event)
            if success:
                logger.info(
                    "Successfully processed transaction: %s (type: %s)",
                    event.transaction_id,
                    event.transaction_type,
                )
            else:
                logger.warning(
                    "Handler returned failure for transaction: %s",
                    event.transaction_id,
                )
            return success
        except Exception as e:
            logger.error(
                "Error processing transaction %s: %s",
                event.transaction_id,
                e,
                exc_info=True,
            )
            return False

    def start(self):
        """Start consuming and processing messages."""
        self._consumer.subscribe(self._topics)
        self._running = True
        logger.info("Started consuming from topics: %s", self._topics)

        try:
            while self._running:
                # Poll for messages
                message_batch = self._consumer.poll(
                    timeout_ms=1000, max_records=100
                )

                for topic_partition, messages in message_batch.items():
                    for message in messages:
                        logger.debug(
                            "Received message from %s partition %d offset %d",
                            topic_partition.topic,
                            topic_partition.partition,
                            message.offset,
                        )

                        success = self._process_message(message.value)

                        if not success:
                            # Log failed messages for dead-letter processing
                            logger.warning(
                                "Failed to process message at offset %d "
                                "from %s partition %d",
                                message.offset,
                                topic_partition.topic,
                                topic_partition.partition,
                            )

                # Commit offsets after processing batch
                if message_batch:
                    try:
                        self._consumer.commit()
                    except Exception as e:
                        logger.error("Failed to commit offsets: %s", e)

        except KeyboardInterrupt:
            logger.info("Received shutdown signal")
        finally:
            self.stop()

    def stop(self):
        """Gracefully stop the consumer."""
        self._running = False
        try:
            self._consumer.close()
            logger.info("Consumer closed gracefully")
        except Exception as e:
            logger.error("Error closing consumer: %s", e)


